from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule_interval="@daily", start_date=datetime(2024, 1, 1), catchup=False)
def my_etl_pipeline():

    @task
    def extract() -> dict:
        # Simulate pulling data from an API
        return {"rows": 1000, "source": "api_v2"}

    @task
    def transform(raw: dict) -> dict:
        # Simulate transformation
        return {"rows_processed": raw["rows"] * 2, "source": raw["source"]}

    @task
    def load(processed: dict):
        print(f"Loading {processed['rows_processed']} rows from {processed['source']}")

    raw_data = extract()
    transformed_data = transform(raw_data)
    load(transformed_data)

my_etl_pipeline()

from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule_interval="@daily", start_date=datetime(2024, 1, 1), catchup=False)
def dynamic_mapping_example():

    @task
    def get_regions() -> list[str]:
        return ["us-east", "eu-west", "ap-south", "us-west"]

    @task
    def process_region(region: str):
        print(f"Processing data for region: {region}")
        # This task runs 4 times, once per region, in parallel

    regions = get_regions()
    process_region.expand(region=regions)

dynamic_mapping_example()

